package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testDisableHtmlEscaping() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially escapeHtmlChars should be true (DEFAULT_ESCAPE_HTML)
    Field escapeHtmlCharsField = GsonBuilder.class.getDeclaredField("escapeHtmlChars");
    escapeHtmlCharsField.setAccessible(true);
    boolean initialValue = escapeHtmlCharsField.getBoolean(builder);
    assertTrue(initialValue, "escapeHtmlChars should initially be true");

    // Call disableHtmlEscaping and verify return value is the same instance
    GsonBuilder returned = builder.disableHtmlEscaping();
    assertSame(builder, returned, "disableHtmlEscaping should return the same GsonBuilder instance");

    // Verify escapeHtmlChars is now false
    boolean afterValue = escapeHtmlCharsField.getBoolean(builder);
    assertFalse(afterValue, "escapeHtmlChars should be false after disableHtmlEscaping");
  }
}
